// Parse the booking JSON from arg1
const input = $input.first().json;
const chat_id = input.chat_id;
const lang = input.lang || 'en';

try {
  const bookingsJson = input.arg1;

  if (!bookingsJson) {
    throw new Error('No booking data provided');
  }

  const bookings = JSON.parse(bookingsJson);

  if (!Array.isArray(bookings) || bookings.length === 0) {
    throw new Error('Booking data must be a non-empty array');
  }

  const validatedBookings = bookings.map((booking, index) => {
    if (!booking.court || !booking.date || !booking.time_start || !booking.time_end || !booking.players_num) {
      throw new Error(`Booking ${index + 1} missing required fields`);
    }

    let dateStr = booking.date;
    let dateMatch = dateStr.match(/^(\d{1,2})\.(\d{1,2})\.(\d{2,4})$/);
    if (dateMatch) {
      const day = dateMatch[1].padStart(2, '0');
      const month = dateMatch[2].padStart(2, '0');
      let year = dateMatch[3];
      if (year.length === 2) {
        year = '20' + year;
      }
      dateStr = `${day}.${month}.${year}`;
    }
    else {
      dateMatch = dateStr.match(/^(\d{4})-(\d{2})-(\d{2})$/);
      if (dateMatch) {
        dateStr = `${dateMatch[3]}.${dateMatch[2]}.${dateMatch[1]}`;
      }
    } 

    return {
      court: booking.court,
      date: dateStr,
      time_start: booking.time_start,
      time_end: booking.time_end,
      players_num: parseInt(booking.players_num),
      notes: booking.notes || ''
    };
  });

  return [{ json: {
    chat_id,
    lang,
    bookings: validatedBookings,
    booking_count: validatedBookings.length
  }}];

} catch (error) {
  return [{ json: {
    chat_id,
    lang,
    error: error.message,
    error_key: 'book_invalid_json'
  }}];
}

// Prepare court_bookings array for bulk reservation API
const context = $('Set Booking Context').first().json;
const bookings = context.bookings;
const session_id = context.session_id;

// Format bookings for put_bulk_reservation API
const court_bookings = bookings.map(booking => ({
  court: String(booking.court),
  date: booking.date,
  time_start: booking.time_start,
  time_end: booking.time_end
}));

return [{
  json: {
    session_id: session_id,
    court_bookings: court_bookings,
    original_bookings: bookings,
    user_id: context.user_id,
    username: context.username,
    fullname: context.fullname,
    chat_id: context.chat_id,
    lang: context.lang
  }
}];

const original_args = $('When Executed by Another Workflow').first().json.arg1;
const bookings = JSON.parse(original_args);
const user_id = $('When Executed by Another Workflow').first().json.user_id;
let queries = [];
const inserted = $input.first().json.result.structuredContent.reservation.bookings;

for (let i = 0; i < inserted.length; i++) {
  const b = bookings[i];
  const reservation_id = inserted[i].booking_id;

  // Convert date from DD.MM.YYYY to YYYY-MM-DD for PostgreSQL DATE column
  let dbDate = b.date;
  const dateMatch = b.date.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})$/);
  if (dateMatch) {
    const day = dateMatch[1].padStart(2, '0');
    const month = dateMatch[2].padStart(2, '0');
    const year = dateMatch[3];
    dbDate = `${year}-${month}-${day}`;
  }

  // Safe notes: handle null/undefined and escape ALL apostrophes
  const safeNotes = (b.notes || '').replace(/'/g, "''");

  const query = "INSERT INTO reservations " +
    "(date, time_start, time_end, court, players_num, user_id, notes, reservation_id) " +
    "VALUES(" +
    "'" + dbDate + "'," +
    "'" + b.time_start + "'," +
    "'" + b.time_end + "'," +
    "'" + b.court + "'," +
    b.players_num + "," +
    "'" + user_id + "'," +
    "'" + safeNotes + "'," +
    "'" + reservation_id + "'" +
    ");";
  queries.push(query);
}

return [{ json: { queries: queries } }];

const bulkContext = $('Prepare Bulk Bookings').first().json;
const inserted = $('MCP Bulk Reservation').first().json.result.structuredContent;
return [{
  json: {
    chat_id: bulkContext.chat_id,
    lang: bulkContext.lang,
    username: bulkContext.username,
    fullname: bulkContext.fullname,
    bookings: bulkContext.original_bookings,
    inserted: inserted,
    success: true
  }
}];

const template = $input.first().json.text;
const context = $('Prepare Success Data').first().json;
const bookings = context.bookings;
const inserted = context.inserted.reservation.bookings;
const username = context.username;
const fullname = context.fullname;

let messages = [];
for (let i = 0; i < inserted.length; i++) {
  const booking = inserted[i];
// bookings.forEach( => {booking
  let msg = template
    .replace('{id}', booking.booking_id)
    .replace('{date}', booking.date)
    .replace('{time_start}', booking.time_start)
    .replace('{time_end}', booking.time_end)
    .replace('{court}', booking.court)
    .replace('{players_num}', bookings[i].players_num)
    .replace('{fullname}', fullname)
    .replace('{notes}', bookings[i].notes || '-');
  messages.push("✅ " + msg);
}

return [{
  json: {
    chat_id: context.chat_id,
    message: messages.join('\n\n---\n\n')
  }
}];

const crypto = require('crypto');
const input = $input.first().json;
const confirmation_id = crypto.randomBytes(8).toString('hex');

// Parse booking slots from arg1 to build confirmation message details
let details = '';
try {
  const slots = JSON.parse(input.arg1);
  if (Array.isArray(slots) && slots.length > 0) {
    details = slots.map(function(s) {
      const courtLabel = s.court ? 'Court ' + s.court : '';
      const dateLabel = s.date || '';
      const timeLabel = (s.time_start && s.time_end) ? s.time_start + '\u2013' + s.time_end : '';
      const playersLabel = s.players_num ? '\ud83d\udc65 ' + s.players_num : '';
      return ('\ud83c\udff8 ' + courtLabel + '  \ud83d\udcc5 ' + dateLabel + '  \u23f0 ' + timeLabel + '  ' + playersLabel).trim();
    }).join('\n');
  }
} catch(e) {
  details = input.arg1 || '';
}

const result = {
  json: {
    chat_id: input.chat_id,
    user_id: input.user_id,
    username: input.username,
    fullname: input.fullname,
    lang: input.lang,
    command: input.command,
    arg1: input.arg1,
    confirmed: input.confirmed,
    confirmation_id: confirmation_id,
    details_text: details
  }
};

return [result];

